import React, { useState } from 'react';
import { useApp } from '../../context/AppContext';
import { STATUS_FLOW, STATUS_CONFIG } from '../../data/mockData';
import StatusBadge from './StatusBadge';
import './WODetailModal.css';

export default function WODetailModal({ wo, onClose }) {
  const { role, updateWOStatus, showToast } = useApp();
  const [rejectNote, setRejectNote] = useState('');
  const [showRejectInput, setShowRejectInput] = useState(false);

  if (!wo) return null;

  const slaPct = Math.min(Math.round((wo.elapsedHours / wo.slaHours) * 100), 100);
  const slaColor = slaPct >= 100 ? 'var(--danger)' : slaPct >= 80 ? 'var(--warning)' : 'var(--success)';
  const currentIdx = STATUS_FLOW.indexOf(wo.status);

  // ── Action handlers ──────────────────────────────────────

  function doAssign() {
    updateWOStatus(wo.id, 'assigned', {
      by: 'Client (Admin)', action: 'Contractor confirmed & assigned',
      note: 'Contractor notified', type: 'default',
    });
    showToast('Contractor assigned — they have been notified');
    onClose();
  }

  function doDelegate() {
    updateWOStatus(wo.id, 'inprogress', {
      by: `Contractor (${role})`, action: 'Delegated to Supervisor',
      note: 'Supervisor and workman allocated', type: 'default',
    });
    showToast('Delegated to supervisor — work in progress');
    onClose();
  }

  function doStartWork() {
    updateWOStatus(wo.id, 'inprogress', {
      by: 'Workman', action: 'Work started on site',
      note: '', type: 'default',
    });
    showToast('Work started — supervisor notified');
    onClose();
  }

  function doMarkDone() {
    updateWOStatus(wo.id, 'qc', {
      by: 'Workman', action: 'Job marked complete — pending supervisor QC',
      note: '', type: 'default',
    });
    showToast('Marked as done — supervisor will review');
    onClose();
  }

  function doPassQC() {
    updateWOStatus(wo.id, 'pending', {
      by: 'Supervisor', action: 'QC passed — submitted for client approval',
      note: 'All checks passed', type: 'default',
    });
    showToast('Submitted for client approval');
    onClose();
  }

  function doApprove() {
    updateWOStatus(wo.id, 'closed', {
      by: 'Client (Admin)', action: 'Approved & Closed',
      note: 'Signed off by client', type: 'closed',
    });
    showToast('Work order approved and closed ✓', 'success');
    onClose();
  }

  function doReject() {
    updateWOStatus(wo.id, 'inprogress', {
      by: 'Client (Admin)', action: 'Rejected — rework required',
      note: rejectNote || 'Sent back to contractor', type: 'default',
    });
    showToast('Work order rejected — contractor notified');
    onClose();
  }

  function doAcknowledge() {
    updateWOStatus(wo.id, 'inprogress', {
      by: 'Client (Admin)', action: 'Escalation acknowledged',
      note: 'Client has taken notice and is monitoring', type: 'default',
    });
    showToast('Escalation acknowledged');
    onClose();
  }

  // ── Role-based action buttons ────────────────────────────
  function renderActions() {
    if (wo.status === 'closed') return null;

    if (role === 'client') {
      if (wo.status === 'open')      return <button className="btn btn-primary" onClick={doAssign}>Confirm &amp; Assign</button>;
      if (wo.status === 'escalated') return <button className="btn btn-primary" onClick={doAcknowledge}>Acknowledge Escalation</button>;
      if (wo.status === 'pending') return (
        <>
          {showRejectInput ? (
            <div style={{ display:'flex', gap:8, alignItems:'center', flex:1 }}>
              <input
                className="form-input"
                style={{ flex:1, padding:'5px 10px', fontSize:12 }}
                placeholder="Reason for rejection..."
                value={rejectNote}
                onChange={e => setRejectNote(e.target.value)}
              />
              <button className="btn btn-danger btn-sm" onClick={doReject}>Confirm Reject</button>
              <button className="btn btn-sm" onClick={() => setShowRejectInput(false)}>Cancel</button>
            </div>
          ) : (
            <>
              <button className="btn btn-success" onClick={doApprove}>Approve &amp; Close</button>
              <button className="btn btn-danger" onClick={() => setShowRejectInput(true)}>Reject</button>
            </>
          )}
        </>
      );
    }

    if (role === 'contractor') {
      if (wo.status === 'assigned') return <button className="btn btn-primary" onClick={doDelegate}>Delegate to Supervisor</button>;
    }

    if (role === 'supervisor') {
      if (wo.status === 'inprogress') return <button className="btn btn-primary" onClick={doPassQC}>Pass QC — Send for Approval</button>;
    }

    if (role === 'workman') {
      if (wo.status === 'assigned')   return <button className="btn btn-primary" onClick={doStartWork}>Start Work</button>;
      if (wo.status === 'inprogress') return <button className="btn btn-primary" onClick={doMarkDone}>Mark as Done</button>;
    }

    return null;
  }

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal wo-modal">

        {/* Header */}
        <div className="modal-header">
          <div>
            <span style={{ fontSize:12, color:'var(--text-3)', fontWeight:500 }}>{wo.id}</span>
            <div className="modal-title">{wo.title}</div>
          </div>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>

        {/* Body */}
        <div className="modal-body">

          {/* Escalation alert */}
          {wo.status === 'escalated' && (
            <div className="alert alert-danger">
              ⚠ This work order breached its {wo.slaHours}h SLA and has been auto-escalated.
              Immediate action required.
            </div>
          )}

          {/* SLA warning */}
          {wo.status !== 'closed' && wo.status !== 'escalated' && slaPct >= 80 && (
            <div className="alert alert-warning">
              ⚠ {slaPct}% of the {wo.slaHours}h SLA has elapsed. Act promptly.
            </div>
          )}

          {/* Status flow */}
          <div className="status-flow">
            {STATUS_FLOW.map((s, i) => {
              let cls = '';
              if (wo.status === 'escalated') cls = i === 0 ? 'done' : '';
              else if (i < currentIdx) cls = 'done';
              else if (i === currentIdx) cls = 'current';
              return (
                <React.Fragment key={s}>
                  <span className={`sf-step ${cls}`}>{STATUS_CONFIG[s].label}</span>
                  {i < STATUS_FLOW.length - 1 && <span className="sf-arrow">›</span>}
                </React.Fragment>
              );
            })}
            {wo.status === 'escalated' && (
              <>
                <span className="sf-arrow">›</span>
                <span className="sf-step current" style={{ background:'var(--danger-bg)', color:'var(--danger)', borderColor:'var(--danger-border)' }}>Escalated</span>
              </>
            )}
          </div>

          {/* Details grid */}
          <div className="detail-grid">
            <div className="detail-item"><div className="dl">Status</div><div className="dv"><StatusBadge status={wo.status} /></div></div>
            <div className="detail-item"><div className="dl">Priority</div><div className="dv" style={{ color: wo.priority==='High'?'var(--danger)':wo.priority==='Med'?'var(--warning)':'var(--text-2)', fontWeight:600 }}>{wo.priority}</div></div>
            <div className="detail-item"><div className="dl">Contractor</div><div className="dv">{wo.contractor}</div></div>
            <div className="detail-item"><div className="dl">Supervisor</div><div className="dv">{wo.supervisor}</div></div>
            <div className="detail-item"><div className="dl">Workman</div><div className="dv">{wo.workman}</div></div>
            <div className="detail-item"><div className="dl">Area / Zone</div><div className="dv">{wo.area}</div></div>
            <div className="detail-item"><div className="dl">Category</div><div className="dv">{wo.category}</div></div>
            <div className="detail-item"><div className="dl">Raised By</div><div className="dv">{wo.raisedBy}</div></div>
            <div className="detail-item"><div className="dl">Raised On</div><div className="dv">{wo.raisedOn}</div></div>
            <div className="detail-item"><div className="dl">Due Date</div><div className="dv" style={{ color: wo.due==='27 Apr'?'var(--danger)':'inherit' }}>{wo.due}</div></div>
          </div>

          {/* SLA bar */}
          <div className="section-heading">SLA Progress</div>
          <div style={{ marginBottom:18 }}>
            <div style={{ display:'flex', justifyContent:'space-between', marginBottom:5, fontSize:12 }}>
              <span style={{ color:'var(--text-2)' }}>Elapsed: <strong>{wo.elapsedHours}h</strong> of {wo.slaHours}h</span>
              <span style={{ color: slaColor, fontWeight:600 }}>{slaPct}%{slaPct >= 100 ? ' — BREACHED' : ''}</span>
            </div>
            <div className="sla-bar-wrap">
              <div className="sla-bar" style={{ width: `${slaPct}%`, background: slaColor }} />
            </div>
          </div>

          {/* Description */}
          <div className="section-heading">Description</div>
          <div style={{ fontSize:13, color:'var(--text-2)', padding:'10px 12px', background:'var(--bg)', borderRadius:'var(--radius)', marginBottom:4, lineHeight:1.6 }}>
            {wo.description}
          </div>

          {/* Activity log */}
          <div className="section-heading">Activity Log</div>
          <div className="timeline">
            {wo.activity.map((entry, i) => (
              <div className="timeline-item" key={entry.id}>
                <div className="tl-dot-wrap">
                  <div className={`tl-dot ${entry.type || 'default'}`} />
                  {i < wo.activity.length - 1 && <div className="tl-line" />}
                </div>
                <div className="tl-content">
                  <div className="tl-action">{entry.action}</div>
                  <div className="tl-meta">{entry.time} · {entry.by}</div>
                  {entry.note && <div className="tl-note">"{entry.note}"</div>}
                </div>
              </div>
            ))}
          </div>

        </div>

        {/* Footer */}
        <div className="modal-footer">
          <button className="btn" onClick={onClose}>Close</button>
          {renderActions()}
        </div>

      </div>
    </div>
  );
}
